#invoiceBox {
  font-family: inherit;
  background: #FFFFFF;
  border: 1px solid #E5E7EB;
  border-radius: 12px;
  padding: 24px 28px;
}

.invoice-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  border-bottom: 1px solid #E5E7EB;
  padding-bottom: 16px;
  margin-bottom: 20px;
}

.invoice-title {
  font-size: 22px;
  font-weight: 700;
  color: #05042E;
}

.invoice-subtitle {
  font-size: 13px;
  color: #469BC0;
}

#printBtn {
  display: flex;
  align-items: center;
  gap: 6px;
  background: #00C170;
  color: #05042E;
  border: none;
  padding: 9px 16px;
  border-radius: 8px;
  font-weight: 700;
  font-size: 13px;
  cursor: pointer;
}

#printBtn:hover {
  opacity: 0.9;
}

.invoice-summary {
  display: flex;
  gap: 32px;
  background: #F8FAFC;
  border-radius: 10px;
  padding: 16px 20px;
  margin-bottom: 20px;
}

.summary-block .label {
  display: block;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  color: #64748B;
  font-weight: 600;
  margin-bottom: 4px;
}

.summary-block .value {
  font-size: 28px;
  font-weight: 700;
  color: #05042E;
}

.invoice-meta {
  display: flex;
  justify-content: space-between;
  gap: 24px;
  margin-bottom: 24px;
}

.invoice-meta .label {
  display: block;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  color: #64748B;
  font-weight: 600;
  margin-bottom: 4px;
}

.invoice-meta .value {
  font-size: 14px;
  font-weight: 600;
  color: #1F2937;
}

#customerInput {
  border: 1px solid #D1D5DB;
  border-radius: 6px;
  padding: 6px 10px;
  font-size: 14px;
  width: 180px;
}

.invoice-ref {
  font-size: 32px;
  font-weight: 700;
  letter-spacing: 0.02em;
  color: #05042E;
  margin-bottom: 16px;
}

#invoiceTable {
  width: 100%;
  border-collapse: collapse;
}

#invoiceTable th {
  text-align: left;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  color: #64748B;
  font-weight: 600;
  padding: 10px 8px;
  border-bottom: 1px solid #E5E7EB;
}

#invoiceTable td {
  padding: 10px 8px;
  font-size: 13px;
  border-bottom: 1px solid #F1F5F9;
}

@media print {
  #printBtn {
    display: none;
  }
}

