function escHtml(str) {
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
function render() {
  const m = appsmith.model || {};
  const header = m.header;
  const items = Array.isArray(m.items) ? m.items : [];
  if (!header) return;
  const isDirectSale = header.platform === 'Direct Sale';
  const customerInput = document.getElementById('customerInput');
  customerInput.value = isDirectSale ? header.customer_name || '' : header.platform;
  customerInput.disabled = !isDirectSale;
  customerInput.style.background = isDirectSale ? '#FFFFFF' : '#F1F5F9';
  document.getElementById('saleDate').textContent = header.sale_date ? new Date(header.sale_date).toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  }) : '';
  document.getElementById('createdBy').textContent = header.created_by || '';
  document.getElementById('saleRef').textContent = header.sale_ref || '';
  document.getElementById('itemCount').textContent = items.length;
  const total = items.reduce(function (sum, it) {
    return sum + Number(it.sell_price || 0);
  }, 0);
  document.getElementById('totalValue').textContent = '£' + total.toFixed(2);
  document.getElementById('invoiceTbody').innerHTML = items.map(function (item) {
    return '<tr>' + '<td>' + escHtml(item.asset_ref) + '</td>' + '<td>' + escHtml(item.make_name) + ' ' + escHtml(item.model_name) + '</td>' + '<td>' + escHtml(item.serial_number) + '</td>' + '<td>£' + Number(item.sell_price || 0).toFixed(2) + '</td>' + '</tr>';
  }).join('');
}
appsmith.onReady(function () {
  render();
  document.getElementById('printBtn').onclick = function () {
    window.print();
  };
});
appsmith.onModelChange(render);

